sql:
SELECT COUNT(*) AS institution_count
FROM institutions
WHERE country = 'Canada';

SELECT country, COUNT(*) AS number_of_institutions
FROM institutions
GROUP BY country;

SELECT campus_location
FROM campuses
WHERE institution_id = 0;

external_knowledge:
